/**
 * Header_Base Theme Core Module
 * ماژول اصلی مدیریت تم Header_Base با ساختار مدرن
 */
class Header_BaseThemeCore {
    constructor() {
        this.init();
    }

    /**
     * راه‌اندازی اولیه
     */
    init() {
        this.setupGlobals();
        this.checkStorageSupport();
        this.setupHelpers();
        this.setupElementorIntegration();
        this.setupPreloader();
        this.setupFocusManagement();
        this.setupEventTriggers();
    }

    /**
     * تنظیم متغیرهای گلوبال
     */
    setupGlobals() {
        // jQuery References
        this.$window = jQuery(window);
        this.$document = jQuery(document);
        this.$body = jQuery('body');

        // Window Properties
        this.windowWidth = this.$window.width();

        // Global Module
        window.Header_BaseThemeModule = this;
    }

    /**
     * بررسی پشتیبانی از Web Storage
     */
    checkStorageSupport() {
        this.supports_html5_storage = false;

        try {
            this.supports_html5_storage =
                'sessionStorage' in window &&
                window.sessionStorage !== null;

            // Test storage functionality
            window.sessionStorage.setItem('wd_test', 'test');
            window.sessionStorage.removeItem('wd_test');
        } catch (error) {
            console.warn('HTML5 Storage not supported:', error);
            this.supports_html5_storage = false;
        }
    }

    /**
     * تنظیم توابع کمکی
     */
    setupHelpers() {
        // URL Parameter Remover
        this.removeURLParameter = this.createURLParameterRemover();

        // Style Cleaner
        this.removeDuplicatedStylesFromHTML = this.createStyleCleaner();

        // Debounce Function
        this.debounce = this.createDebounceFunction();

        // Animation Functions
        this.setupSlideAnimations();

        // Google Maps Callback
        this.googleMapsCallback = () => '';
    }

    /**
     * ایجاد تابع حذف پارامتر از URL
     */
    createURLParameterRemover() {
        return function (url, paramName) {
            const urlParts = url.split('?');

            if (urlParts.length < 2) {
                return url;
            }

            const baseUrl = urlParts[0];
            const paramPrefix = encodeURIComponent(paramName) + '=';
            const params = urlParts[1].split(/[&;]/g);

            // Filter out the parameter to remove
            const filteredParams = params.filter(param =>
                !param.startsWith(paramPrefix)
            );

            // Reconstruct URL
            return filteredParams.length > 0
                ? `${baseUrl}?${filteredParams.join('&')}`
                : baseUrl;
        };
    }

    /**
     * ایجاد تابع تمیزکننده استایل‌های تکراری
     */
    createStyleCleaner() {
        return function (htmlContent, callback) {
            const $tempWrapper = jQuery('<div class="temp-wrapper"></div>')
                .append(htmlContent);

            const $links = $tempWrapper.find('link[rel="stylesheet"]');

            // No stylesheets found
            if ($links.length === 0) {
                callback(htmlContent);
                return;
            }

            let processedCount = 0;
            let isCompleted = false;

            // Timeout fallback
            const fallbackTimeout = setTimeout(() => {
                if (!isCompleted) {
                    callback(jQuery($tempWrapper.html()));
                    isCompleted = true;
                }
            }, 500);

            // Process each stylesheet
            $links.each((index, link) => {
                const $link = jQuery(link);
                const linkId = $link.attr('id');
                const linkHref = $link.attr('href');

                // Remove from temporary wrapper
                $link.remove();

                const isThemeStyle = linkId && linkId.includes('theme_settings_');
                const isDefaultTheme = linkId && linkId.includes('theme_settings_default');

                // Check if already loaded
                const isAlreadyLoaded = window.Header_Base_page_css &&
                    window.Header_Base_page_css[linkId];

                if (isAlreadyLoaded || isDefaultTheme) {
                    this.processLinkCompletion();
                    return;
                }

                // Add to head and wait for load
                jQuery('head').append(
                    $link.on('load', this.processLinkCompletion.bind(this))
                );

                // Cache the stylesheet
                if (isThemeStyle && window.Header_Base_page_css) {
                    window.Header_Base_page_css[linkId] = linkHref;
                }
            }.bind(this));

            /**
             * Helper: Mark link as processed
             */
            function processLinkCompletion() {
                processedCount++;

                if (processedCount >= $links.length && !isCompleted) {
                    clearTimeout(fallbackTimeout);
                    callback(jQuery($tempWrapper.html()));
                    isCompleted = true;
                }
            }
        };
    }

    /**
     * ایجاد تابع Debounce
     */
    createDebounceFunction() {
        return function (func, wait, immediate) {
            let timeout;

            return function executedFunction() {
                const context = this;
                const args = arguments;

                const later = function () {
                    timeout = null;
                    if (!immediate) {
                        func.apply(context, args);
                    }
                };

                const callNow = immediate && !timeout;

                clearTimeout(timeout);
                timeout = setTimeout(later, wait);

                if (callNow) {
                    func.apply(context, args);
                }
            };
        };
    }

    /**
     * تنظیم توابع انیمیشن Slide
     */
    setupSlideAnimations() {
        // Slide Up
        this.slideUp = function (element, duration = 400) {
            if (!element) return;

            element.style.transitionProperty = 'height, margin, padding';
            element.style.transitionDuration = `${duration}ms`;
            element.style.boxSizing = 'border-box';
            element.style.height = `${element.offsetHeight}px`;

            // Trigger reflow
            element.offsetHeight;

            element.style.overflow = 'hidden';
            element.style.height = '0';
            element.style.paddingTop = '0';
            element.style.paddingBottom = '0';
            element.style.marginTop = '0';
            element.style.marginBottom = '0';

            setTimeout(() => {
                element.style.display = 'none';

                // Clean up styles
                ['height', 'padding-top', 'padding-bottom',
                    'margin-top', 'margin-bottom', 'overflow',
                    'transition-duration', 'transition-property']
                    .forEach(prop => element.style.removeProperty(prop));
            }, duration);
        };

        // Slide Down
        this.slideDown = function (element, duration = 400) {
            if (!element) return;

            element.style.removeProperty('display');
            let display = window.getComputedStyle(element).display;

            if (display === 'none') {
                display = 'block';
            }

            element.style.display = display;

            const height = element.offsetHeight;

            element.style.overflow = 'hidden';
            element.style.height = '0';
            element.style.paddingTop = '0';
            element.style.paddingBottom = '0';
            element.style.marginTop = '0';
            element.style.marginBottom = '0';

            // Trigger reflow
            element.offsetHeight;

            element.style.boxSizing = 'border-box';
            element.style.transitionProperty = 'height, margin, padding';
            element.style.transitionDuration = `${duration}ms`;
            element.style.height = `${height}px`;

            ['padding-top', 'padding-bottom', 'margin-top', 'margin-bottom']
                .forEach(prop => element.style.removeProperty(prop));

            setTimeout(() => {
                ['height', 'overflow', 'transition-duration', 'transition-property']
                    .forEach(prop => element.style.removeProperty(prop));
            }, duration);
        };

        // Slide Toggle
        this.slideToggle = function (element, duration = 400) {
            if (!element) return;

            const display = window.getComputedStyle(element).display;

            if (display === 'none') {
                this.slideDown(element, duration);
            } else {
                this.slideUp(element, duration);
            }
        }.bind(this);
    }

    /**
     * تنظیم یکپارچگی با Elementor
     */
    setupElementorIntegration() {
        // Elementor Action Wrapper
        this.wdElementorAddAction = function (actionName, callback) {
            this.$window.on('elementor/frontend/init', () => {
                if (window.elementorFrontend &&
                    window.elementorFrontend.isEditMode()) {
                    window.elementorFrontend.hooks.addAction(actionName, callback);
                }
            });
        }.bind(this);

        // Global Elementor Ready
        this.wdElementorAddAction('frontend/element_ready/global', ($element) => {
            $element
                .removeClass('wd-animation-ready wd-animated wd-in');

            this.$document.trigger('wdElementorGlobalReady');
        });

        // Column/Container Ready
        ['frontend/element_ready/column', 'frontend/element_ready/container']
            .forEach(action => {
                this.wdElementorAddAction(action, ($element) => {
                    $element
                        .removeClass('wd-animation-ready wd-animated wd-in');

                    setTimeout(() => {
                        this.$document.trigger('wdElementorColumnReady');
                    }, 100);
                });
            });

        // Shop Load More Button Selector
        this.shopLoadMoreBtn = '.wd-products-load-more.load-on-scroll';

        // Elementor Editor Integration
        this.setupElementorEditor();
    }

    /**
     * تنظیمات Elementor Editor
     */
    setupElementorEditor() {
        this.$window.on('elementor/frontend/init', () => {
            if (!window.elementorFrontend ||
                !window.elementorFrontend.isEditMode()) {
                return;
            }

            // Section/Container Setup
            ['frontend/element_ready/section', 'frontend/element_ready/container']
                .forEach(action => {
                    this.wdElementorAddAction(action, ($element) => {
                        $element
                            .removeClass('wd-animation-ready wd-animated wd-in');

                        this.$document.trigger('wdElementorSectionReady');
                    });

                    // Negative Gap Management
                    if (window.elementorFrontend.hooks) {
                        window.elementorFrontend.hooks.addAction(action, ($element) => {
                            const modelCid = $element.data('model-cid');

                            if (!modelCid ||
                                !window.elementorFrontend.config?.elements?.data[modelCid]) {
                                return;
                            }

                            const elementData = window.elementorFrontend.config.elements.data[modelCid];
                            const attributes = elementData.attributes;
                            let shouldHaveNegativeGap = false;

                            if (attributes.elType === 'container') {
                                shouldHaveNegativeGap = attributes.content_width === 'boxed' &&
                                    attributes.boxed_width?.size;
                            } else if (attributes.elType === 'section') {
                                shouldHaveNegativeGap = attributes.content_width?.size;
                            }

                            if (!shouldHaveNegativeGap) {
                                $element.addClass('wd-negative-gap');
                            }
                        });
                    }
                });

            // Editor Change Listener
            if (window.elementor?.channels?.editor) {
                window.elementor.channels.editor.on(
                    'change:section change:container',
                    (event) => {
                        const { elementSettingsModel, _parent } = event;
                        const { changed, attributes } = elementSettingsModel;

                        // Check if width changed
                        if (!changed.content_width && !changed.boxed_width) {
                            return;
                        }

                        let newWidth = null;

                        if (attributes.elType === 'container') {
                            newWidth = changed.boxed_width?.size;
                        } else {
                            newWidth = changed.content_width?.size;
                        }

                        const elementId = _parent.model.id;
                        const $element = jQuery(`.elementor-element-${elementId}`);

                        if (newWidth) {
                            $element.removeClass('wd-negative-gap');
                        } else {
                            $element.addClass('wd-negative-gap');
                        }
                    }
                );
            }
        });
    }

    /**
     * تنظیم Preloader
     */
    setupPreloader() {
        this.$window.on('load', () => {
            // Hide preloader
            jQuery('.wd-preloader')
                .delay(300)
                .addClass('preloader-hide');

            // Remove preloader styles
            jQuery('.wd-preloader-style').remove();

            // Remove preloader from DOM
            setTimeout(() => {
                jQuery('.wd-preloader').remove();
            }, 200);
        });
    }

    /**
     * مدیریت فوکوس برای سایدبارها و منوها
     */
    setupFocusManagement() {
        let previouslyFocusedElement = null;

        // Open Sidebar/Menu
        this.$document.on(
            'wdOpenSide wdOpenSearch',
            '.wd-side-hidden, .wd-fs-menu, [class*="wd-search-full-screen"]',
            function () {
                const $openedElement = jQuery(this);
                previouslyFocusedElement = document.activeElement;

                // Ensure element is focusable
                if (!$openedElement.attr('tabindex')) {
                    $openedElement.attr('tabindex', '-1');
                }

                // Focus the opened element
                $openedElement.trigger('focus');

                // Trap focus inside the element
                jQuery(document).on('focusin.wd', (event) => {
                    if (event.target !== $openedElement[0] &&
                        !$openedElement[0].contains(event.target)) {
                        $openedElement.trigger('focus');
                    }
                });
            }
        );

        // Close Sidebar/Menu
        this.$document.on(
            'wdCloseSide wdCloseSearch',
            '.wd-side-hidden, .wd-fs-menu, [class*="wd-search-full-screen"]',
            function () {
                // Remove focus trap
                jQuery(document).off('focusin.wd');

                // Return focus to previous element
                if (previouslyFocusedElement &&
                    document.contains(previouslyFocusedElement)) {

                    // Adjust focus for quick shop
                    if (previouslyFocusedElement.closest('.wd-quick-shop, .wd-quick-shop-2')) {
                        const productElement = previouslyFocusedElement.closest('.wd-product');
                        if (productElement) {
                            previouslyFocusedElement = productElement.querySelector('.product-image-link');
                        }
                    }

                    jQuery(previouslyFocusedElement).trigger('focus');
                    previouslyFocusedElement = null;
                }
            }
        );

        // Enter key support for tabindex buttons
        this.$document.on('keyup', '.wd-role-btn[tabindex]', (event) => {
            if (event.which === 13) { // Enter key
                jQuery(event.target).trigger('click');
                event.preventDefault();
            }
        });
    }

    /**
     * تنظیم Trigger رویدادهای اولیه
     */
    setupEventTriggers() {
        window.addEventListener('load', () => {
            const activationEvents = [
                'keydown', 'scroll', 'mouseover',
                'touchmove', 'touchstart',
                'mousedown', 'mousemove'
            ];

            const eventHandler = () => {
                // Dispatch initialization event
                window.dispatchEvent(new CustomEvent('wdEventStarted'));

                // Remove all activation listeners
                activationEvents.forEach(eventName => {
                    window.removeEventListener(eventName, eventHandler);
                });
            };

            // Add activation listeners with delay
            setTimeout(() => {
                activationEvents.forEach(eventName => {
                    window.addEventListener(eventName, eventHandler, { once: true });
                });
            }, 100);
        });
    }
}

/**
 * راه‌اندازی خودکار
 */
document.addEventListener('DOMContentLoaded', () => {
    if (typeof jQuery !== 'undefined') {
        window.Header_BaseThemeModule = new Header_BaseThemeCore();
    }
});

/**
 * سازگاری با کد قدیمی
 */
if (typeof jQuery !== 'undefined') {
    jQuery(document).ready(() => {
        if (!window.Header_BaseThemeModule) {
            window.Header_BaseThemeModule = new Header_BaseThemeCore();
        }
    });
}